import{_ as o,o as i,c as l,a3 as r}from"./chunks/framework.CqLY61E_.js";const b=JSON.parse('{"title":"Lab 09 — Sécurité, comptes et privilèges","description":"","frontmatter":{"title":"Lab 09 — Sécurité, comptes et privilèges","aside":true},"headers":[],"relativePath":"labs/lab09-securite.md","filePath":"labs/lab09-securite.md"}'),a={name:"labs/lab09-securite.md"};function s(d,e,t,c,u,n){return i(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="lab-09-—-securite-comptes-et-privileges" tabindex="-1">Lab 09 — Sécurité, comptes et privilèges <a class="header-anchor" href="#lab-09-—-securite-comptes-et-privileges" aria-label="Permalink to &quot;Lab 09 — Sécurité, comptes et privilèges&quot;">​</a></h1><h2 id="objectif-du-laboratoire" tabindex="-1">Objectif du laboratoire <a class="header-anchor" href="#objectif-du-laboratoire" aria-label="Permalink to &quot;Objectif du laboratoire&quot;">​</a></h2><p>Mettre en pratique la création de comptes, de rôles et l&#39;attribution de privilèges directement sur la base de données <strong>Chinook</strong>.</p><h2 id="mise-en-situation" tabindex="-1">Mise en situation <a class="header-anchor" href="#mise-en-situation" aria-label="Permalink to &quot;Mise en situation&quot;">​</a></h2><p>Réalisez la mise en place de la gestion des utilisateurs, des rôles et des privilèges du la base de données <code>Chinook</code> à l&#39;aide des commandes vues dans le module précédent.</p><h2 id="travail-a-realiser" tabindex="-1">Travail à réaliser <a class="header-anchor" href="#travail-a-realiser" aria-label="Permalink to &quot;Travail à réaliser&quot;">​</a></h2><h3 id="_1-creer-les-comptes-et-les-roles" tabindex="-1">1. Créer les comptes et les rôles <a class="header-anchor" href="#_1-creer-les-comptes-et-les-roles" aria-label="Permalink to &quot;1. Créer les comptes et les rôles&quot;">​</a></h3><p>Créez :</p><ul><li>les utilisateurs <code>alice_admin</code>, <code>bob_dev</code>, <code>joe_analyste</code> et <code>app_web</code></li><li>les rôles <code>admin</code>, <code>developpeur</code>, <code>lecture_seule</code></li></ul><p>Puis associez :</p><ul><li><code>alice_admin</code> au rôle <code>admin</code></li><li><code>bob_dev</code> au rôle <code>developpeur</code></li><li><code>joe_analyste</code> au rôle <code>lecture_seule</code></li><li><code>app_web</code> au rôle <code>developpeur</code></li></ul><h3 id="_2-donner-les-droits-de-base-sur-chinook" tabindex="-1">2. Donner les droits de base sur Chinook <a class="header-anchor" href="#_2-donner-les-droits-de-base-sur-chinook" aria-label="Permalink to &quot;2. Donner les droits de base sur Chinook&quot;">​</a></h3><p>Accordez selon le cas :</p><ul><li><code>connect</code> sur la base de données <code>chinook</code></li><li><code>usage</code> sur le schéma <code>public</code></li></ul><h3 id="_3-donner-des-droits-a-l-administrateur" tabindex="-1">3. Donner des droits à l&#39;administrateur <a class="header-anchor" href="#_3-donner-des-droits-a-l-administrateur" aria-label="Permalink to &quot;3. Donner des droits à l&#39;administrateur&quot;">​</a></h3><p>Le rôle <code>admin</code> doit pouvoir :</p><ul><li>se connecter à la base de données</li><li>accéder au schéma <code>public</code></li><li>créer des objets dans la base de données de travail</li><li>gérer largement les objets du schéma <code>public</code></li></ul><p>Pour garder le laboratoire simple, donnez-lui des droits étendus sur les tables et séquences du schéma <code>public</code>.</p><p>Rappel :</p><ul><li><code>admin</code> n&#39;est pas automatiquement un superutilisateur PostgreSQL</li></ul><h3 id="_4-donner-des-droits-realistes-au-developpeur" tabindex="-1">4. Donner des droits réalistes au développeur <a class="header-anchor" href="#_4-donner-des-droits-realistes-au-developpeur" aria-label="Permalink to &quot;4. Donner des droits réalistes au développeur&quot;">​</a></h3><p>Le rôle <code>developpeur</code> doit pouvoir :</p><ul><li>lire les données de Chinook</li><li>insérer, modifier et supprimer des données dans Chinook</li></ul><p>Pour garder le laboratoire simple, donnez ces droits globalement sur toutes les tables du schéma <code>public</code>.</p><p>Si vous donnez des droits d&#39;insertion sur des tables utilisant des séquences, pensez aussi aux séquences nécessaires.</p><h3 id="_5-donner-des-droits-realistes-a-joe-analyste" tabindex="-1">5. Donner des droits réalistes à joe_analyste <a class="header-anchor" href="#_5-donner-des-droits-realistes-a-joe-analyste" aria-label="Permalink to &quot;5. Donner des droits réalistes à joe_analyste&quot;">​</a></h3><p>Le rôle <code>lecture_seule</code> doit pouvoir :</p><ul><li>consulter les données</li><li>sans pouvoir les modifier</li></ul><p>Donnez-lui donc un accès en lecture seule sur toutes les tables du schéma <code>public</code>.</p><h3 id="_6-verifier-le-cas-du-compte-applicatif" tabindex="-1">6. Vérifier le cas du compte applicatif <a class="header-anchor" href="#_6-verifier-le-cas-du-compte-applicatif" aria-label="Permalink to &quot;6. Vérifier le cas du compte applicatif&quot;">​</a></h3><p>Le compte <code>app_web</code> hérite ici du rôle <code>developpeur</code>.</p><p>Vérifiez donc qu&#39;il peut :</p><ul><li>lire les données de Chinook</li><li>insérer, modifier et supprimer des données selon les droits accordés au rôle <code>developpeur</code></li></ul><p>Mais il ne doit toujours pas pouvoir :</p><ul><li>modifier la structure</li><li>agir comme administrateur (ex.: créer des tables)</li></ul><h3 id="_7-revoquer-un-droit" tabindex="-1">7. Révoquer un droit <a class="header-anchor" href="#_7-revoquer-un-droit" aria-label="Permalink to &quot;7. Révoquer un droit&quot;">​</a></h3><p>Retirez ensuite un privilège déjà accordé.</p><p>Exemple concret :</p><ul><li>retirer <code>delete</code> au rôle <code>developpeur</code> sur <code>facture</code></li></ul><p>Question :</p><ul><li>pourquoi retirer <code>delete</code> peut-il être une bonne idée sur certaines tables ?</li></ul><h3 id="_8-valider-le-tout-dans-postgresql" tabindex="-1">8. Valider le tout dans PostgreSQL <a class="header-anchor" href="#_8-valider-le-tout-dans-postgresql" aria-label="Permalink to &quot;8. Valider le tout dans PostgreSQL&quot;">​</a></h3><p>Vérifiez votre configuration :</p><ul><li>voir les rôles existants</li><li>voir qui est connecté</li><li>voir les privilèges sur les tables</li><li>tester ce qu&#39;un rôle peut faire avec <code>set role</code></li></ul><p>Tests suggérés :</p><ul><li>avec <code>admin</code>, essayer un <code>create table test_admin (...)</code></li><li>avec <code>lecture_seule</code>, faire un <code>select</code> sur <code>client</code></li><li>avec <code>lecture_seule</code>, essayer un <code>update</code> sur <code>client</code></li><li>avec <code>developpeur</code>, faire un <code>select</code> sur <code>piste</code></li><li>avec <code>developpeur</code>, essayer un <code>delete</code> sur <code>facture</code></li></ul><h2 id="quelques-questions-de-reflexion" tabindex="-1">Quelques questions de réflexion <a class="header-anchor" href="#quelques-questions-de-reflexion" aria-label="Permalink to &quot;Quelques questions de réflexion&quot;">​</a></h2><ul><li>Pourquoi est-il préférable de donner les droits au rôle <code>developpeur</code> ou <code>lecture_seule</code> plutôt qu&#39;aux comptes directement ?</li><li>Pourquoi un rôle <code>admin</code> avec beaucoup de <code>grant</code> n&#39;est-il pas équivalent à un superutilisateur PostgreSQL ?</li><li>Pourquoi un compte applicatif ne devrait-il pas recevoir <code>all privileges</code> sur Chinook ?</li><li>Pourquoi <code>connect</code> sur la base de données ne suffit-il pas, à lui seul, pour lire ou modifier les tables ?</li></ul><hr>',49)])])}const h=o(a,[["render",s]]);export{b as __pageData,h as default};
